const webhookData = $('Webhook').first().json.body;

const fileData = $input.first().json;
let dv2Rules;
try {
  if (fileData.data) {
    dv2Rules = JSON.parse(Buffer.from(fileData.data, 'base64').toString('utf-8'));
  } else if (fileData.json) {
    dv2Rules = typeof fileData.json === 'string' ? JSON.parse(fileData.json) : fileData.json;
  } else {
    dv2Rules = fileData;
  }
} catch (e) {
  dv2Rules = fileData;
}

return {
  json: {
    vault_tables: webhookData.vault_tables,
    mart_table_name: webhookData.mart_table_name,
    grain: webhookData.grain,
    metrics: webhookData.metrics || [],
    business_keys: webhookData.business_keys || [],
    mart_sql_plan: webhookData.mart_sql_plan || null,
    previous_error: webhookData.previous_error || null,
    retry_instructions: webhookData.retry_instructions || null,
    vault_registry: webhookData.vault_registry || [],
    mart_registry: webhookData.mart_registry || [],
    dv2_rules: dv2Rules
  }
};

