const llmOutput = $input.first().json.text;

let parsed;
try {
  parsed = JSON.parse(llmOutput);
} catch (e) {
  let jsonStr = llmOutput;
  const fenceMatch = llmOutput.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fenceMatch) {
    jsonStr = fenceMatch[1].trim();
  } else if (llmOutput.startsWith('```')) {
    jsonStr = llmOutput.replace(/^```(?:json)?\s*/, '').trim();
  }

  try {
    parsed = JSON.parse(jsonStr);
  } catch (e2) {
    let recovered = jsonStr;
    const quoteCount = (recovered.match(/(?<!\\)"/g) || []).length;
    if (quoteCount % 2 !== 0) recovered += '"';
    const stack = [];
    for (const ch of recovered) {
      if (ch === '{' || ch === '[') stack.push(ch);
      else if (ch === '}' || ch === ']') stack.pop();
    }
    while (stack.length > 0) {
      const last = stack.pop();
      recovered += last === '{' ? '}' : ']';
    }
    try {
      parsed = JSON.parse(recovered);
    } catch (e3) {
      throw new Error('Could not parse LLM output as JSON: ' + llmOutput.substring(0, 300));
    }
  }
}

// Be tolerant about slightly different JSON shapes.
// The LLM should return { mart_table: { table_name, ddl, populate_sql } },
// but sometimes it returns those fields at the top level.
if (!parsed.mart_table) {
  if (parsed.table_name && parsed.ddl && parsed.populate_sql) {
    parsed = { mart_table: parsed };
  } else if (parsed.mart_table_name && parsed.ddl && parsed.populate_sql) {
    parsed = {
      mart_table: {
        table_name: parsed.mart_table_name,
        ddl: parsed.ddl,
        populate_sql: parsed.populate_sql,
      },
    };
  } else if (parsed.table && parsed.ddl && parsed.populate_sql) {
    parsed = {
      mart_table: {
        table_name: parsed.table,
        ddl: parsed.ddl,
        populate_sql: parsed.populate_sql,
      },
    };
  }
}

if (!parsed.mart_table) {
  throw new Error('LLM output missing mart_table object');
}

const mart = parsed.mart_table;
if (!mart.table_name || !mart.ddl || !mart.populate_sql) {
  throw new Error('Mart table entry missing required fields: table_name, ddl, or populate_sql');
}

return {
  json: {
    status: 'success',
    mart_table: mart
  }
};
